//   name: header-modifier
//   namespace: istio-system
// spec:
//   selector:
//     matchLabels:
//       istio: ingressgateway
//   phase: AUTHN
//   inlineCode: |
//     function envoy_on_request(request_handle)
//       request_handle:headers():add("x-custom-header", "added-by-lua")
//     end
// ```
//
